// // This module is a 32-bit demultiplexer that outputs one of two 32-bit input buses based on a 1-bit select signal.
module mux_2_to_1 (
    input [31:0] in0,
    input [31:0] in1,
    input sel,
    output reg [31:0] out
);
    always @(*) begin
        if (sel) 
            out = in1;
        else 
            out = in0;
    end
endmodule
